MERGE INTO CONSULTAS FIN USING (SELECT '000814INFRELGRALTRASLADOS' INFORME ,TO_CLOB(q'[SELECT COMPROBANTE_CNT.FECHA, 
       COMPROBANTE_CNT.TIPO,
       COMPROBANTE_CNT.DESCRIPCION DETALLE, 
       COMPROBANTE_CNT.VLRAGIRAR VALORGIRAR 
FROM COMPROBANTE_CNT 
WHERE COMPROBANTE_CNT.COMPANIA = s$compania$s 
  AND COMPROBANTE_CNT.ANO      = s$anio$s 
  AND COMPROBANTE_CNT.MES      = s$mes$s
  AND COMPROBANTE_CNT.TIPO     IN (s$tipoCompTraslados$s)]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);